import SwiftUI

private let kApiBaseURL = "__VIBETREE_API_BASE_URL__"
private let kAppToken = "__VIBETREE_APP_TOKEN__"
private let kCacheInterval: TimeInterval = 30 * 60

struct OWMResponse: Codable {
    let name: String?
    let main: Main?
    let weather: [WeatherItem]?
    struct Main: Codable { let temp: Double?; let humidity: Int?; let feels_like: Double? }
    struct WeatherItem: Codable { let main: String?; let description: String? }
}

@MainActor
class WeatherViewModel: ObservableObject {
    @Published var cityName: String = ""
    @Published var temp: Double?
    @Published var condition: String?
    @Published var isLoading = false
    @Published var errorMessage: String?
    private var lastFetchTime: Date?
    private var cachedCity: String?

    func fetchWeather(city: String) {
        let trimmed = city.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return }
        if let cached = cachedCity, cached == trimmed, let time = lastFetchTime, Date().timeIntervalSince(time) < kCacheInterval {
            isLoading = false; errorMessage = nil; return
        }
        var comp = URLComponents(string: kApiBaseURL + "/api/proxy/weather")
        comp?.queryItems = [URLQueryItem(name: "city", value: trimmed), URLQueryItem(name: "type", value: "current")]
        guard let url = comp?.url else { errorMessage = "Invalid URL"; return }
        var request = URLRequest(url: url)
        request.setValue(kAppToken, forHTTPHeaderField: "X-App-Token")
        isLoading = true
        errorMessage = nil
        Task {
            do {
                let (data, response) = try await URLSession.shared.data(for: request)
                guard let http = response as? HTTPURLResponse else { errorMessage = "Invalid response"; isLoading = false; return }
                switch http.statusCode {
                case 401: errorMessage = "Please sign in"; isLoading = false; return
                case 429: errorMessage = "Too many requests"; isLoading = false; return
                case 200...299:
                    let owm = try JSONDecoder().decode(OWMResponse.self, from: data)
                    lastFetchTime = Date(); cachedCity = trimmed
                    cityName = trimmed; temp = owm.main?.temp; condition = owm.weather?.first?.description
                    errorMessage = nil
                default:
                    let err = (try? JSONDecoder().decode([String: String].self, from: data))?["error"] ?? "Weather error"
                    errorMessage = err
                }
                isLoading = false
            } catch {
                errorMessage = error.localizedDescription
                isLoading = false
            }
        }
    }
}

struct WeatherView: View {
    @StateObject private var viewModel = WeatherViewModel()
    @State private var cityInput = "San Francisco"
    var body: some View {
        VStack(spacing: 12) {
            TextField("City", text: $cityInput).textFieldStyle(.roundedBorder).padding(.horizontal)
            Button("Get weather") { viewModel.fetchWeather(city: cityInput) }
            if viewModel.isLoading { ProgressView("Loading…") }
            else if let msg = viewModel.errorMessage { Text(msg).foregroundStyle(.red) }
            else if let temp = viewModel.temp {
                VStack(spacing: 8) {
                    Text(viewModel.cityName).font(.headline)
                    Text("\(Int(temp))°F").font(.largeTitle)
                    if let c = viewModel.condition { Text(c).font(.subheadline) }
                }
            }
        }
        .padding()
        .onAppear { viewModel.fetchWeather(city: cityInput) }
    }
}

