import SwiftUI
import CoreLocation

private let kApiBaseURL = "__VIBETREE_API_BASE_URL__"
private let kAppToken = "__VIBETREE_APP_TOKEN__"
private let kLocationTimeout: TimeInterval = 15
private let kFallbackLat = 32.78
private let kFallbackLon = -79.93
private let kCacheInterval: TimeInterval = 30 * 60

struct OWMResponse: Codable {
    let name: String?
    let main: Main?
    let weather: [WeatherItem]?
    struct Main: Codable { let temp: Double?; let humidity: Int?; let feels_like: Double? }
    struct WeatherItem: Codable { let main: String?; let description: String? }
}

// Location coordinator: set delegate BEFORE requestWhenInUseAuthorization, 15s timeout, fallback coords, didUpdateLocations triggers callback.
final class LocationCoordinator: NSObject, ObservableObject {
    private let manager = CLLocationManager()
    private var fallbackWorkItem: DispatchWorkItem?
    @Published var isLocating = false
    @Published var didFailOrTimeout = false
    var onLocation: ((CLLocation) -> Void)?

    func requestLocation() {
        manager.delegate = self
        manager.requestWhenInUseAuthorization()
        manager.startUpdatingLocation()
        isLocating = true
        didFailOrTimeout = false
        fallbackWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in self?.useFallback() }
        fallbackWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + kLocationTimeout, execute: work)
    }

    private func useFallback() {
        fallbackWorkItem = nil
        manager.stopUpdatingLocation()
        let loc = CLLocation(latitude: kFallbackLat, longitude: kFallbackLon)
        DispatchQueue.main.async {
            self.onLocation?(loc)
            self.isLocating = false
            self.didFailOrTimeout = true
        }
    }
}

extension LocationCoordinator: CLLocationManagerDelegate {
    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let loc = locations.last else { return }
        fallbackWorkItem?.cancel()
        fallbackWorkItem = nil
        manager.stopUpdatingLocation()
        DispatchQueue.main.async {
            self.onLocation?(loc)
            self.isLocating = false
            self.didFailOrTimeout = false
        }
    }

    func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        useFallback()
    }
}

@MainActor
class WeatherWithLocationViewModel: ObservableObject {
    @Published var cityName: String = ""
    @Published var temp: Double?
    @Published var condition: String?
    @Published var isLoading = false
    @Published var errorMessage: String?
    private var lastFetchTime: Date?
    private var lastLat: Double?
    private var lastLon: Double?

    func fetchWeather(lat: Double, lon: Double) {
        if let t = lastFetchTime, let la = lastLat, let lo = lastLon, la == lat, lo == lon, Date().timeIntervalSince(t) < kCacheInterval {
            isLoading = false
            return
        }
        var comp = URLComponents(string: kApiBaseURL + "/api/proxy/weather")
        comp?.queryItems = [
            URLQueryItem(name: "lat", value: String(lat)),
            URLQueryItem(name: "lon", value: String(lon)),
            URLQueryItem(name: "type", value: "current")
        ]
        guard let url = comp?.url else { errorMessage = "Invalid URL"; return }
        var request = URLRequest(url: url)
        request.setValue(kAppToken, forHTTPHeaderField: "X-App-Token")
        isLoading = true
        errorMessage = nil
        Task {
            do {
                let (data, response) = try await URLSession.shared.data(for: request)
                guard let http = response as? HTTPURLResponse else { errorMessage = "Invalid response"; isLoading = false; return }
                switch http.statusCode {
                case 401: errorMessage = "Please sign in"; break
                case 429: errorMessage = "Too many requests"; break
                case 200...299:
                    let owm = try JSONDecoder().decode(OWMResponse.self, from: data)
                    lastFetchTime = Date(); lastLat = lat; lastLon = lon
                    temp = owm.main?.temp
                    condition = owm.weather?.first?.description
                    errorMessage = nil
                default:
                    errorMessage = (try? JSONDecoder().decode([String: String].self, from: data))?["error"] ?? "Weather error"
                }
                isLoading = false
            } catch {
                errorMessage = error.localizedDescription
                isLoading = false
            }
        }
    }
}

struct WeatherWithLocationView: View {
    @StateObject private var viewModel = WeatherWithLocationViewModel()
    @StateObject private var locationCoordinator = LocationCoordinator()

    var body: some View {
        VStack(spacing: 12) {
            if locationCoordinator.isLocating {
                ProgressView("Locating you…")
            } else if locationCoordinator.didFailOrTimeout && viewModel.temp == nil {
                Button("Use current location") { locationCoordinator.requestLocation() }
            }
            if viewModel.isLoading { ProgressView("Loading…") }
            else if let msg = viewModel.errorMessage { Text(msg).foregroundStyle(.red) }
            else if let temp = viewModel.temp {
                VStack(spacing: 8) {
                    Text(viewModel.cityName).font(.headline)
                    Text("\(Int(temp))°F").font(.largeTitle)
                    if let c = viewModel.condition { Text(c).font(.subheadline) }
                }
            }
        }
        .padding()
        .onAppear {
            locationCoordinator.onLocation = { loc in
                viewModel.fetchWeather(lat: loc.coordinate.latitude, lon: loc.coordinate.longitude)
                CLGeocoder().reverseGeocodeLocation(loc) { placemarks, _ in
                    DispatchQueue.main.async {
                        viewModel.cityName = placemarks?.first?.locality ?? "Current Location"
                    }
                }
            }
            locationCoordinator.requestLocation()
        }
    }
}
